"""
MKT Original Commentary — Luke chapter 8
Run: python3 scripts/zc-original-luke-8-8.py

Source data used:
- data/interlinear/luke.json
- data/translation/draft/mediating/luke.json
- data/translation/glossary-greek.json

Key decisions in this range:
- v.10: Isa 6:9-10 allusion for parable-purpose; "ta mysteria" (mysteries/secrets)
  is the Danielic-apocalyptic term for divine revelation given to insiders.
- v.15: "kardia kale kai agathe" is the Hellenistic moral-philosophy ideal
  (kalos-kagathos = noble and good) adapted by Luke for a Gentile-facing audience.
- v.30: "Legiōn" — Roman military unit (~6,000 soldiers); the name is simultaneously
  the demon's and a comment on Roman occupation as demonic presence in Gentile territory.
- v.43: Luke omits Mark 5:26 ("spent all she had on physicians and grew worse");
  possibly editorial restraint from the physician-author.
- v.44: "kraspedou" — hem/fringe of garment; possibly the tzitzit (Num 15:38-40),
  making faith-contact with the visible symbol of Torah-obedience.
- v.48: "sesōken" — perfect active: has saved/healed; sozo covers both physical healing
  and spiritual salvation in Luke (cf. 7:50; 17:19; 18:42).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE = {
  "8": {
    "1": '<p><strong>kai egeneto en tō kathexēs kai autos diōdeuev kata polin kai kōmēn</strong> — he was traveling through city after city and village after village — <em>kathexēs</em> (in sequence, successively) is a Lukan word (cf. 1:3; Acts 3:24; 11:4; 18:23) marking ordered narrative progression. <em>Diōdeuō</em> (to travel through, journey through) describes systematic evangelistic itineration. <strong>kēryssōn kai euangelizomenos tēn basileian tou theou</strong> — proclaiming and announcing the good news of the kingdom of God — Luke pairs <em>kēryssōn</em> (herald-proclamation) and <em>euangelizomenos</em> (good-news announcement); together they cover both the public announcement and the content-specific glad tidings.</p>',
    "2": '<p><strong>kai gynaikes tines hai ēsan tetherapeumenai apo pneumatōn ponērōn kai astheneiōn</strong> — and certain women who had been healed of evil spirits and diseases — Luke alone records the band of women disciples who traveled with Jesus and supported the movement. <em>Tetherapeumenai</em> (perfect passive participle: having been and remaining healed) marks the healings as permanent. <strong>Mariam hē kaloumenē Magdalēnē</strong> — Mary called the Magdalene — <em>Magdalēnē</em> identifies her town of origin: Magdala/Taricheae on the western shore of the Sea of Galilee, a prosperous fishing-processing center. <strong>aph hēs daimonia hepta exelēlythei</strong> — from whom seven demons had gone out — seven (<em>hepta</em>) is the number of completeness; the exorcism was total.</p>',
    "3": '<p><strong>kai Iōanna gynē Chyza epitropou Hērōdou</strong> — and Joanna wife of Chuza, Herod\'s steward — <em>epitropos</em> (steward, manager, administrator) is a high-ranking household official; Chuza managed Herod Antipas\'s personal estate. Joanna\'s presence in the apostolic company indicates access to the Herodian court — a significant intelligence and social network connection. <strong>hai diekonoun autois ek tōn hyparchontōn autais</strong> — they were serving/supporting them out of their own possessions — <em>diakonoun</em> (were serving, ministering — the diakonia vocabulary) and <em>hyparchontōn</em> (possessions, resources) indicate material patronage. Women of means are the financial foundation of Jesus\'s itinerant movement.</p>',
    "4": '<p><strong>syniontos de ochlou pollou kai tōn kata polin epiporeouomenōn pros auton</strong> — a large crowd coming together and those from each city traveling to him — the composite audience arrives from multiple directions; Luke emphasizes the drawing power of Jesus before the parable begins. <strong>eipen dia parabolēs</strong> — he spoke by a parable — <em>parabolē</em> (comparison, figurative speech, riddle) is the Synoptic term for Jesus\'s characteristic teaching mode; it derives from the Hebrew <em>mashal</em> (proverb, parable, simile), which covered wisdom comparisons, riddles, and extended analogies. The parable is not primarily didactic illustration but an invitation to discernment.</p>',
    "5": '<p><strong>exēlthen ho speirōn tou speirai ton sporon autou</strong> — the sower went out to sow his seed — the indefinite article is absent in Greek: <em>ho speirōn</em> is simply "the sower" as a type, not a specific identified individual. <em>Speirōn</em>/<em>speirō</em> (sowing) was broadcast by hand in the ancient Near East; the sower scattered seed widely before plowing, so some inevitably fell on unintended soil. <strong>kai en tō speirein auton ho men epesen para tēn hodon</strong> — and in his sowing, some fell along the road — <em>para tēn hodon</em> (beside/along the path) is the hard-packed edge of agricultural fields where foot traffic compacted the soil; seed lying on the surface became bird-food.</p>',
    "6": '<p><strong>kai heteron katepesen epi tēn petran</strong> — other seed fell on the rock — <em>petra</em> (bedrock, solid rock) covered by a thin layer of soil; sufficient for germination but not for root development. <strong>kai phylen exaranthe dia to mē echein ikmada</strong> — and growing up it withered because it had no moisture — <em>ikmada</em> (moisture, dampness) is Luke\'s unique word here (vs. Matthew/Mark\'s "depth of earth"); a medical-sounding term for the soil\'s hydration level. The Palestinian summer rapidly desiccates shallow-rooted seedlings; without moisture access from depth, the young plant cannot survive the dry season.</p>',
    "7": '<p><strong>kai heteron epesen en mesō tōn akanthōn</strong> — other seed fell in the middle of the thorns — <em>akanthai</em> (thorns, thorn-bushes) were perennial plants whose root systems occupied the soil before plowing; their growth season paralleled the grain crop. <strong>kai symphyeisai hai akanthai apepnixan auto</strong> — and the thorns growing up with it choked it — <em>symphyō</em> (to grow up together with, co-grow) and <em>apopnigō</em> (to choke, strangle, cut off air) describe competitive growth that starves the good plant of light and nutrients. Luke\'s interpretation (v.14) identifies these as the cares, wealth, and pleasures of life.</p>',
    "8": '<p><strong>kai heteron epesen eis tēn gēn tēn agathēn kai phyen epoiēsen karpon hekatontaplasiōna</strong> — other seed fell into the good earth and growing up produced fruit a hundredfold — <em>gēn tēn agathēn</em> (good earth) — deep, prepared, fertile soil. <em>Hekatontaplasiōna</em> (a hundred times over, hundredfold) is an extraordinary yield; Palestinian grain farming averaged 10-fold returns; 30-fold was good; 100-fold is extraordinary enough to suggest the eschatological abundance of the new era (cf. Gen 26:12 where Isaac reaped hundredfold as divine blessing). <strong>tauta legōn ephōnei, Ho echōn ōta akouein akouetō</strong> — saying these things he called out: the one having ears to hear, let them hear — the hearing-summons marks the parable as requiring discernment, not merely comprehension.</p>',
    "9": '<p><strong>epērōtōn de auton hoi mathētai autou tis autē eiē hē parabolē</strong> — his disciples were asking him what this parable might mean — <em>epērōtaō</em> (to ask, question, interrogate) indicates persistent inquiry; the imperfect suggests ongoing questioning. <em>Tis autē eiē hē parabolē</em> (what this parable might be — optative mood) is an indirect question in the optative, Luke\'s more refined literary style (vs. Mark\'s simpler constructions). The disciples\' question is genuine incomprehension, not Socratic pretense; the parable\'s meaning is not transparent on the surface.</p>',
    "10": '<p><strong>ho de eipen, Hymin dedotai gnōnai ta mystēria tēs basileias tou theou</strong> — he said: to you it has been given to know the mysteries of the kingdom of God — <em>ta mystēria</em> (the mysteries, secrets) is the Danielic-apocalyptic term for divine revelations disclosed to the elect but hidden from others (cf. Dan 2:18-19,27-30,47; 1QS III-IV). The passive <em>dedotai</em> (has been given, divine passive) locates the source of understanding in God, not human insight. <strong>tois de loipois en parabolais, hina blepontes mē blepōsin kai akouontes mē syniosin</strong> — to the rest in parables, so that seeing they may not see and hearing they may not understand — Isa 6:9 (LXX), the commissioning text for prophetic ministry to a hardened audience.</p>',
    "11": '<p><strong>estin de hautē hē parabolē, Ho sporos estin ho logos tou theou</strong> — this is the parable: the seed is the word of God — <em>ho logos tou theou</em> (the word of God) is the identification Luke consistently applies to Jesus\'s proclamation and later to the apostolic gospel in Acts (Acts 4:31; 6:2,7; 8:14; 11:1; 12:24; 13:7; 17:13; 18:11). The equation seed = the word of God makes the parable an allegory of reception and rejection of divine address. The sower is not identified in Luke\'s interpretation (unlike some subsequent traditions); the focus is entirely on the soil/reception conditions.</p>',
    "12": '<p><strong>hoi de para tēn hodon eisin hoi akousantes, eita erchetai ho diabolos kai airei ton logon apo tēs kardias autōn</strong> — those along the road are those who heard, then the devil comes and takes the word from their heart — Luke\'s interpretation names <em>ho diabolos</em> (the devil) explicitly where Mark has "Satan"; this matches Luke\'s preference established from 4:2. <em>Airei ton logon apo tēs kardias</em> (lifts/takes the word from their heart) explains the birds of the parable as active demonic removal of what was heard; the word never penetrates beyond surface hearing. <strong>hina mē pisteusantes sōthōsin</strong> — so that they might not believe and be saved — the purpose is damning: the devil\'s action prevents the believing that leads to salvation (<em>soteria</em>).</p>',
    "13": '<p><strong>hoi de epi tēs petras, hoi hotan akousōsin meta charas dechovtai ton logon</strong> — those on the rock are those who, when they hear, receive the word with joy — <em>meta charas</em> (with joy) is an enthusiastic initial reception; the problem is structural, not motivational. <strong>kai houtoi rizan ouk echousin</strong> — and these have no root — <em>rizan ouk echousin</em> (have no root) is the depth metaphor for settled conviction; surface enthusiasm without deep formation. <strong>pros kairon pisteuousin kai en kairō peirasmou afistantai</strong> — they believe for a season and in a time of testing they fall away — <em>kairō peirasmou</em> (time of testing/temptation) is the crucible that reveals the rootlessness; <em>aphistantai</em> (fall away, depart, apostatize — the <em>apostasia</em> root) is Luke\'s strongest term for abandonment of faith.</p>',
    "14": '<p><strong>to de eis tas akanthas peson, houtoi eisin hoi akousantes kai hypo merimnōn kai ploutou kai hēdonōn tou biou poreuomenoi symphygontai</strong> — the seed fallen among thorns are those who heard and going on their way are choked by anxieties and wealth and pleasures of life — Luke\'s triad <em>merimna</em> (anxiety, care), <em>ploutos</em> (wealth, riches), and <em>hēdonai tou biou</em> (pleasures of life) maps the competitive forces against the word. <em>Sympnigō</em> (to choke, strangle) describes the gradual suffocation of spiritual vitality. <strong>kai ou telesphorousin</strong> — and they do not bring to maturity — <em>telesphorō</em> (to bring to full fruition, complete development) is unique to Luke; the image is of fruit that begins but never ripens to harvestable completeness.</p>',
    "15": '<p><strong>to de en tē kalē gē, houtoi eisin hoitines en kardia kalē kai agathē</strong> — those in the good earth are those who have a noble and good heart — <em>kardia kalē kai agathē</em> (noble and good heart) is the Hellenistic moral ideal: <em>kalos</em> (beautiful, honorable) and <em>agathos</em> (good, morally excellent) together form the classical <em>kalos kagathos</em> ideal of the fully formed ethical person. Luke adapts this Hellenistic virtue language for a Greek-speaking audience; Matthew and Mark lack this phrase. <strong>akousantes ton logon katechousin kai karpophorous in en hypomonē</strong> — having heard the word they hold fast and bear fruit in perseverance — <em>katechō</em> (to hold fast, retain) and <em>hypomonē</em> (endurance, perseverance under pressure) are the two marks of productive reception.</p>',
    "16": '<p><strong>Oudeis de lychon hapsas kalyptei auton skeuei ē hypokato klinēs tithēsin</strong> — no one lighting a lamp covers it with a vessel or places it under a bed — the lamp saying appears in a different context than Matthew\'s (Sermon on the Mount, Mt 5:15) and Mark\'s (Mk 4:21); Luke places it after the sower-interpretation to apply the revelation principle: what has been disclosed is for illumination, not concealment. <em>Lychon</em> (lamp, oil lamp) is the household clay lamp; <em>lychnia</em> (lampstand) elevates it for maximum distribution of light. <strong>hina hoi eiserchomenoi blepōsin to phōs</strong> — so that those entering may see the light — the incoming visitor benefits from the lamp placed for visibility.</p>',
    "17": '<p><strong>ou gar estin krypton ho ou phaneron genēsetai</strong> — for there is nothing hidden that will not become visible — the principle grounds the lamp saying: hiddenness is provisional and purposeful, not permanent. <strong>oude apokryphon ho ou mē gnōsthē kai eis phaneron elthē</strong> — and nothing concealed that will not be known and come into the open — <em>apokryphos</em> (hidden away, concealed) is the technical term for esoteric knowledge; Luke applies it to the parables\' concealment. The revelation of the kingdom\'s mysteries (v.10) is ultimately public, not permanently esoteric. The saying functions as both promise (truth will emerge) and warning (all concealed things will be disclosed).</p>',
    "18": '<p><strong>blepete oun pōs akouete</strong> — take care therefore how you hear — <em>pōs akouete</em> (how you hear, in what manner you hear) is Luke\'s distinctive formulation; Mark and Matthew have "what you hear." The quality and manner of hearing determines what is received; the same words produce different effects in different hearers. <strong>hos an gar echē, dothēsetai autō; kai hos an mē echē, kai ho dokei echein arthēsetai ap autou</strong> — for whoever has, it will be given to him; and whoever does not have, even what he thinks he has will be taken from him — the paradox of spiritual economy: active receptivity generates accumulation; passive possession erodes. <em>Ho dokei echein</em> (what he thinks he has) reveals the illusion of superficial reception.</p>',
    "19": '<p><strong>parageonto de pros auton hē mētēr kai hoi adelphoi autou</strong> — his mother and brothers came to him — the <em>adelphoi</em> (brothers) of Jesus are named in Mk 6:3 as James, Joseph, Judas, and Simon; whether biological brothers, half-brothers, or cousins depends on one\'s view of Mary\'s perpetual virginity. <strong>kai ouk ēdynanto syntychein autō dia ton ochlon</strong> — and they could not reach him because of the crowd — physical inaccessibility creates the occasion for the pronouncement about spiritual family that follows. Luke\'s version (unlike Mark 3:21,31-35) removes any hint that the family came because they thought Jesus was out of his mind; Luke presents the scene neutrally.</p>',
    "20": '<p><strong>apēngelē de autō, Hē mētēr sou kai hoi adelphoi sou hestēkasin exō idein se thelontes</strong> — it was reported to him: your mother and brothers are standing outside wishing to see you — the message is relayed through the crowd rather than spoken directly; the physical distance mirrors the coming pronouncement about relational distance. <em>Hestēkasin</em> (are standing, perfect participle = have taken a position and remain there) indicates they are waiting, not hostile. The message creates a teaching moment rather than reporting a crisis.</p>',
    "21": '<p><strong>ho de apokritheis eipen pros autous, Mētēr mou kai adelphoi mou houtoi eisin hoi ton logon tou theou akouontes kai poiountes</strong> — he answered and said to them: my mother and my brothers are those who hear the word of God and do it — the redefinition of family is based on the parable\'s criterion (vv.15, "hear the word and hold fast") now applied relationally. <em>Akouontes kai poiountes</em> (hearing and doing) is the James-and-Jesus ethical summary (cf. Jas 1:22-25); the two-part criterion reflects Deut 6:3 (hear and do). The biological family is not excluded but the covenant family of disciples supersedes biological claims. <em>Ho logos tou theou</em> binds vv.11-21 into a unity.</p>',
    "22": '<p><strong>egeneto de en mia tōn hēmerōn kai autos enebē eis ploion kai hoi mathētai autou</strong> — one day he got into a boat with his disciples — the sea-crossing narrative begins: the lake crossing to the eastern (predominantly Gentile) shore is a geographical transition with theological significance. <strong>kai eipen pros autous, Dielthōmen eis to peran tēs limnēs</strong> — he said to them: let us cross to the other side of the lake — <em>to peran</em> (the other side) in the Synoptics regularly marks the crossing to Gentile territory (the Decapolis). <strong>kai anēchthēsan</strong> — and they set sail — <em>anagō</em> (to bring up, to put to sea) is a nautical term; the verb is common in Luke-Acts for sea voyages (Acts 13:13; 16:11; 18:21; 20:3,13).</p>',
    "23": '<p><strong>pleonton de autōn aphypnōsen</strong> — as they sailed, he fell asleep — <em>aphypnoō</em> (to fall deeply asleep) is used only here in the NT; it implies sound, undisturbed sleep — not fitful dozing. The detail is theologically charged: Jesus sleeps in the storm as Jonah slept in the ship (Jon 1:5-6), but where Jonah\'s sleep was negligence, Jesus\'s sleep is sovereignty. <strong>kai katebē lailaps anemou eis tēn limnēn kai syneplērounto kai ekindyneuon</strong> — a squall came down onto the lake and they were filling with water and were in danger — <em>lailaps</em> (violent squall, whirlwind-storm) is the technical term for the sudden katabatic storms that descend from the Golan Heights onto the Sea of Galilee.</p>',
    "24": '<p><strong>proselthontes de diegeiron auton legontes, Epistata, epistata, apollymetha</strong> — going to him they woke him saying: Master, Master, we are perishing — <em>Epistata</em> doubled (<em>Epistata, Epistata</em>) is the urgent Lukan cry of disciples in crisis (cf. 17:13 ten lepers calling <em>Iēsou epistata</em>); it expresses both urgency and deference to his authority. <strong>ho de egertheis epetimēsen tō anemō kai tō klydonī tou hydatos</strong> — waking up he rebuked the wind and the surging of the water — <em>epetimēsen</em> (rebuked) is the same verb used against demons (4:35,41; 9:42) and fever (4:39); Luke treats the storm as subject to the same divine command that expels demons. <strong>kai egeneto galēnē</strong> — and there was a calm — <em>galēnē</em> (calm, tranquility at sea) is the technical Greek term for a windless sea surface.</p>',
    "25": '<p><strong>eipen de autois, Pou hē pistis hymōn</strong> — he said to them: where is your faith? — the question is diagnostic: not "where were you?" but "where is the <em>pistis</em> (faith, trust, reliance) that should have sustained you?" The disciples\' failure was not the fear itself but the absence of trust in the one sleeping in the boat. <strong>phobēthentes de ethaumasan legontes pros allēlous, Tis ara houtos estin</strong> — they were afraid and marveled, saying to one another: who then is this? — <em>Tis ara houtos estin</em> (who therefore is this?) is the Christological question the miracle raises without immediately answering. <strong>hoti kai tois anemois epitassei kai tō hydati, kai hypakouousin autō</strong> — because he commands even the winds and the water and they obey him — divine control over sea and storm is YHWH\'s prerogative in the OT (Ps 107:23-32; Job 38:8-11).</p>',
    "26": '<p><strong>kai katepleusan eis tēn chōran tōn Gerasēnōn</strong> — they sailed down to the region of the Gerasenes — <em>Gerasēnōn</em> is the reading of most manuscripts (cf. the textual variant <em>Gadarēnōn</em> in Matthew 8:28 and some Luke manuscripts, and <em>Gergesēnōn</em> in a few). Gerasa (modern Jerash in Jordan) is ~50km from the lake — too far geographically, but may refer to a district rather than the city. <strong>hētis estin antiperan tēs Galilaias</strong> — which is across from Galilee — Luke\'s explanatory gloss for Gentile readers who would not know the eastern shore\'s geography; it marks the crossing to Gentile territory as completed.</p>',
    "27": '<p><strong>exelthonti de autō epi tēn gēn hypēntēsen anēr tis ek tēs poleōs</strong> — when he stepped ashore, a certain man from the city met him — the immediate encounter before Jesus can reach any populated area underscores the severity of the case: the demoniac comes out to meet him. <strong>hos eichen daimonia kai chronō hikanō ouk enedysato himation</strong> — who had demons and for a long time had not worn clothing — <em>chronō hikanō</em> (for a considerable time, a long time) emphasizes the chronic, severe nature of the possession. Nakedness marks the loss of human dignity and social identity. <strong>kai en oikia ouk emenev alla en tois mnēmasin</strong> — and he was not staying in a house but in the tombs — dwelling among the dead (the unclean, ritually defiling tombs) is the ultimate marginalization from human community.</p>',
    "28": '<p><strong>idōn de ton Iēsoun anakraxas prosepesen autō</strong> — seeing Jesus he cried out and fell before him — <em>anakrazō</em> (to cry out, shout aloud) is the involuntary vocalization of the demon encountering divine power (cf. 4:33-34). <em>Prosepesen autō</em> (fell before him) is the same prostration used for Peter (5:8) and the leper (5:12); the demon compels the man into the position of a suppliant. <strong>kai phōnē megalē eipen, Ti emoi kai soi, Iēsou Huie tou Theou tou Hypsistou</strong> — with a loud voice he said: what to me and to you, Jesus Son of God Most High? — <em>Hypsistos</em> (Most High) is the Hellenistic Jewish title for YHWH (Gen 14:18-20; Num 24:16; Dan 3:26), also used by Gentiles for the supreme deity. The title bridges Jewish and Gentile theological categories.</p>',
    "29": '<p><strong>parēggeilen gar tō pneumati tō akathartō exelthein apo tou anthrōpou</strong> — for he had commanded the unclean spirit to come out of the man — Luke explains the demon\'s outcry by giving the backstory: Jesus had already issued the command before the verbal exchange. The pluperfect <em>parēggeilen</em> (had commanded) places the command prior to the dialogue. <strong>pollois gar chronois synerpakei auton</strong> — for many times it had seized him — <em>synarpazō</em> (to seize, sweep away — a violent verb for sudden attack) is Luke\'s medical term for seizure (cf. Acts 6:12; 19:29; 27:15 for "swept away"). The chains and shackles broken by the demoniac\'s supernatural strength indicate chronic violent episodes known to the community.</p>',
    "30": '<p><strong>epērōtēsen de auton ho Iēsous legōn, Ti soi onoma estin</strong> — Jesus asked him: what is your name? — the question is not for Jesus\'s information but for the man\'s own benefit and for the audience\'s comprehension. Knowing a demon\'s name was associated in ancient exorcism practice with gaining power over it (cf. PGM IV.1265-74); Jesus does not need the name to exorcise but asks publicly to expose the magnitude of the possession. <strong>ho de eipen, Legiōn, hoti eisēlthen daimonia polla eis auton</strong> — he said: Legion, because many demons had entered into him — <em>Legiōn</em> is the Latin loanword for a Roman military unit of 5,000-6,000 soldiers; the name simultaneously reveals the severity of possession (a multitude) and, for Luke\'s audience, evokes Roman military occupation as a demonic presence.</p>',
    "31": '<p><strong>kai parekalei auton hina mē epitaxē autois eis tēn abysson apelthein</strong> — they were begging him not to command them to go into the Abyss — <em>abyssos</em> (the Abyss, the bottomless pit) is the eschatological prison for rebellious spirits (cf. Rev 9:1-2,11; 20:1-3; 1 Enoch 18:12-16; Jubilees 5:6-10). In Jewish apocalyptic, the Abyss is the pre-appointed confinement for fallen angels awaiting final judgment; the demons\' terror of it reveals their knowledge of their ultimate fate. Their request to avoid it is a request for a temporary reprieve from their eschatological sentence.</p>',
    "32": '<p><strong>ēn de ekei agelē choirōn hikanōn boskomenē en tō orei</strong> — there was a large herd of pigs feeding on the hillside — pigs (<em>choiroi</em>) are ritually impure animals (Lev 11:7; Deut 14:8) whose presence confirms the Gentile territory; a Jewish settlement would not keep swine herds. <em>Hikanōn</em> (considerable, large) indicates a substantial commercial herd. <strong>kai parekaleson auton hina epitrepsē autois eis ekeinous eiselthein</strong> — they begged him to allow them to enter into those — the demons negotiate: not the Abyss, but the swine herd. Jesus\'s permission (<em>epetrepsen autois</em>) raises the question of why he grants it; the outcome (the herd\'s destruction) may be the answer: even the "concession" serves the man\'s liberation.</p>',
    "33": '<p><strong>exelthonta de ta daimonia apo tou anthrōpou eisēlthen eis tous choirous</strong> — coming out of the man, the demons entered the pigs — the transfer is immediate upon Jesus\'s permission. <strong>kai hōrmēsen hē agelē kata tou krēmnou eis tēn limnēn kai apepnigē</strong> — and the herd rushed down the steep bank into the lake and was drowned — <em>hormaō</em> (to rush, charge — used of a herd stampeding) and <em>krēmnos</em> (steep bank, cliff) describe the uncontrolled plunge. <em>Apepnigē</em> (was choked, drowned) echoes the "choked" plants of v.14 (thorns); the demons\' final state is drowning/choking — the same fate they inflict on the word in human hearts. The lake that was a crisis for the disciples (vv.22-25) is now the destruction of the demonic horde.</p>',
    "34": '<p><strong>idontes de hoi boskontes to gegenēmenon ephygon kai apēngeilan eis tēn polin kai eis tous agrous</strong> — seeing what had happened, those tending them fled and reported in the city and in the fields — the herdsmen are eyewitnesses who became involuntary evangelists; their flight and report follow the pattern of those who encounter divine power and cannot contain the news. <em>To gegenēmenon</em> (what had happened, perfect participle: the event now present as a completed reality) is the Lukan summary phrase for miraculous events (cf. 2:15; 24:12). The report goes both to the <em>polis</em> (city, urban center) and to the <em>agroi</em> (fields, rural areas).</p>',
    "35": '<p><strong>exēlthan de idein to gegenēmenon kai ēlthon pros ton Iēsoun kai heuron kathēmenon ton anthrōpon</strong> — they went out to see what had happened and came to Jesus and found the man sitting — the transformation is visible: the man who was naked, among the tombs, shouting, and breaking chains is now <strong>kathēmenon himatimusemon kai sōphronounta</strong> — sitting, clothed, and in his right mind. <em>Sōphroneō</em> (to be in one\'s right mind, sane, self-controlled) is the mark of restored humanity; <em>para tous podas tou Iēsou</em> (at the feet of Jesus) is the posture of a disciple or a healed person in grateful proximity. <strong>kai ephobēthēsan</strong> — and they were afraid — the community\'s response to the restoration is fear, not joy; the disruption of the known order is more alarming than the restoration of the afflicted man.</p>',
    "36": '<p><strong>apēngeilan de autois hoi idontes pōs esōthē ho daimonistheis</strong> — those who had seen told them how the demon-possessed man had been saved — <em>esōthē</em> (was saved, healed — aorist passive of <em>sōzō</em>) applies Luke\'s salvation vocabulary to the exorcism: the man\'s liberation from demonic possession is described with the same term used for forgiveness of sins (7:50) and physical healing (8:48; 17:19; 18:42). The observers\' report (<em>hoi idontes</em> = eyewitness testimony) is the basis of the community\'s knowledge of the event.</p>',
    "37": '<p><strong>kai ērōtēsen auton hapan to plēthos tēs perichōrou tōn Gerasēnōn apelthein ap autōn, hoti phobō megalō syneichonto</strong> — the whole multitude of the surrounding region of the Gerasenes asked him to depart from them, because they were gripped by great fear — <em>hapan to plēthos</em> (the whole multitude) — unanimous rejection. <em>Phobō megalō syneichonto</em> (were gripped by great fear) — <em>sunechō</em> (to grip, compress, constrain) + <em>phobos megas</em> (great fear) describes a community traumatized by an encounter with divine power beyond their framework. The Gerasenes prefer to lose the possessed man than to live with the one who cured him; the power that heals is more threatening than the power that destroys. <strong>autos de embas eis ploion hyestrepsen</strong> — he got into the boat and returned.</p>',
    "38": '<p><strong>edeito de autou ho anēr aph hou exelēlythei ta daimonia einai syn autō</strong> — the man from whom the demons had gone out begged to be with him — <em>edeito</em> (was begging, entreating — imperfect of earnest request) from the man who has most reason to desire proximity to his deliverer. <em>Einai syn autō</em> (to be with him) is the language of discipleship (cf. Mk 3:14 "that they might be with him"); the man wants to join the traveling company. <strong>apelysen de auton legōn</strong> — but he sent him away saying — <em>apolyō</em> (to release, send away, dismiss) is a deliberate decision; Jesus does not grant the request to travel with him but issues an alternative commission.</p>',
    "39": '<p><strong>Hypóstrephe eis ton oikon sou kai diēgou hosa epoiēsen soi ho Theos</strong> — return to your house and recount all that God has done for you — the man is commissioned as a witness in his own community. <em>Diēgeomai</em> (to narrate, recount in full) is Luke\'s historiographical verb (cf. 1:1; Acts 8:33; 9:27); the former demoniac is to give a full account. The commission to Gentile territory contrasts with the silence commands in Jewish contexts (4:41; 5:14; 8:56); the Gerasene region is the appropriate place for a Gentile witness. <strong>kai apēlthen kath holēn tēn polin kēryssōn hosa epoiēsen autō ho Iēsous</strong> — and he went through the whole city proclaiming what Jesus had done for him — he obeys and expands the commission; "what God did" becomes "what Jesus did" — a Christological equivalence Luke records without comment.</p>',
    "40": '<p><strong>en de tō hypostrephein ton Iēsoun apedexato auton ho ochlos</strong> — when Jesus returned, the crowd welcomed him — the contrast is sharp: the Gerasenes expelled Jesus; the Galilean crowd welcomes him. <em>Apodechomai</em> (to welcome, receive with approval — a word for the proper reception of a guest or dignitary) indicates prepared expectation. <strong>ēsan gar pantes prosdokōntes auton</strong> — for they were all waiting for him — <em>prosdokaō</em> (to wait, expect, look for) indicates the crowd had remained in anticipation of his return. His absence had not dissipated their attention; it had intensified it.</p>',
    "41": '<p><strong>kai idou ēlthen anēr ō onoma Iaeiros kai houtos archōn tēs synagōgēs hypērchen</strong> — a man came whose name was Jairus, and this man was a ruler of the synagogue — <em>archōn tēs synagōgēs</em> (ruler/head of the synagogue) was the lay administrator responsible for building upkeep, service order, and inviting readers and teachers; a position of social standing and communal trust. Jairus is named — a named supplicant in Luke whose petition we can track. <strong>kai pesōn para tous podas Iēsou parekalei auton eiselthein eis ton oikon autou</strong> — falling at Jesus\'s feet he begged him to come to his house — the posture of falling at the feet (<em>pesōn para tous podas</em>) is the posture of the leper (5:12), the demoniac (8:35), and later the grateful Samaritan leper (17:16).</p>',
    "42": '<p><strong>hoti thygatēr monogenēs ēn autō hōs etōn dōdeka kai autē apethnēsken</strong> — because he had an only daughter of about twelve years and she was dying — <em>monogenēs</em> (only-born, only child) is Luke\'s distinctive term for the special grief of sole-child bereavement (cf. 7:12 the widow\'s son; 9:38 the epileptic boy — all three unique to Luke). Twelve years (<em>hōs etōn dōdeka</em>) is the age of Bar/Bat Mitzvah preparation — at the threshold of adult covenant membership. <strong>en de tō hypagein auton hoi ochloi synepnigon auton</strong> — as he was going, the crowds were pressing him — <em>synpnigō</em> (to press together, choke — the same verb as thorns choking the seed in v.7) describes the physical crush; the delay created by the bleeding woman is not coincidental to the intercalation structure.</p>',
    "43": '<p><strong>kai gynē ousa en rhysei haimatos apo etōn dōdeka</strong> — a woman who had been in a flow of blood for twelve years — the twelve-year duration precisely mirrors Jairus\'s daughter\'s twelve-year age; Luke\'s intercalation pairs the two cases. <em>Rhysis haimatos</em> (flow of blood) would have rendered the woman ritually impure continuously under Levitical law (Lev 15:19-30; m. Niddah), excluding her from temple worship, communal meals, and physical contact with others. <strong>hētis iathrois prosanalōsasa holon ton bion ouk ischysen therapeuthenai apo oudenos</strong> — who had spent her whole livelihood on physicians and could not be healed by anyone — Luke\'s restraint: he omits Mark\'s detail that she grew worse under physicians\' care (Mk 5:26), perhaps the restraint of a physician-author.</p>',
    "44": '<p><strong>proselthous opisthen hēpsato tou kraspedou tou himatiou autou</strong> — coming up behind him she touched the edge/fringe of his garment — <em>kraspedon</em> (the edge, hem, fringe — in Jewish usage, the <em>tzitzit</em>/tassel mandated in Num 15:38-40 and Deut 22:12 as a visible reminder of Torah commandments). Touching the <em>kraspedon</em> may be deliberate contact with the symbol of covenant faithfulness; the healing flows through what represents Torah observance. <strong>kai parachrēma estē hē rhysis tou haimatos autēs</strong> — and immediately her flow of blood stopped — <em>parachrēma</em> (immediately) is Luke\'s signature word for instantaneous miraculous healing; <em>estē</em> (aorist: stopped, stood still) signals the cessation of a twelve-year hemorrhage in an instant.</p>',
    "45": '<p><strong>kai eipen ho Iēsous, Tis ho hapsamenous mou</strong> — Jesus said: who touched me? — the question is not ignorance but pedagogical disclosure: Jesus draws the woman out for a public declaration of what happened and why. <strong>arnoumenōn de pantōn eipen ho Petros, Epistata, hoi ochloi synechousin se kai apothlibousin</strong> — when all denied it, Peter said: Master, the crowds are pressing and crushing you — <em>Epistata</em> (Master — Luke\'s title for Jesus in disciple-speech) and Peter\'s pragmatic observation capture the disciples\' puzzlement: physical contact from dozens, yet Jesus asks who touched him. The distinction Jesus draws is between incidental contact and intentional faith-contact.</p>',
    "46": '<p><strong>ho de Iēsous eipen, Hēpsato mou tis, egō gar egnōn dynamin exelēlythuian ap emou</strong> — Jesus said: someone touched me, for I knew power had gone out from me — <em>Dynamin exelēlythuian ap emou</em> (power having gone out from me — perfect participle indicating completed action with present result) is Luke\'s explanation of the mechanism: <em>dynamis</em> (power, Spirit-energy) flows from Jesus to the recipient. This is not automatic or impersonal — Jesus perceives the flow. The perfect participle emphasizes that the power transfer is already complete; the healing has already occurred before this conversation. Jesus does not identify the woman to shame her but to name the faith that triggered the healing.</p>',
    "47": '<p><strong>idousa de hē gynē hoti ouk elathen, tremousa ēlthen kai prosesousa autō</strong> — the woman, seeing that she had not escaped notice, trembling came and fell before him — <em>tremousa</em> (trembling) is the bodily response to exposure before the holy; she expected, perhaps, to slip away unnoticed after the healing. <em>Prosesousa autō</em> (falling before him) is the posture of reverence before divine power. <strong>di hēn aitian hēpsato autou apēngeilen enōpion pantos tou laou kai hōs iathē parachrēma</strong> — she declared before all the people why she had touched him and how she was healed immediately — her public testimony is compelled; what had been a private act of faith becomes a public witness.</p>',
    "48": '<p><strong>ho de eipen autē, Thygater, hē pistis sou sesōken se; poreuou eis eirēnēn</strong> — he said to her: Daughter, your faith has saved/healed you; go in peace — <em>Thygater</em> (Daughter) is a term of warm relational inclusion; Jesus addresses her as a member of the family of God, not merely a healed patient. <em>Hē pistis sou sesōken se</em> (your faith has saved/healed you — perfect active: has saved and the salvation remains) uses <em>sōzō</em>, Luke\'s comprehensive salvation term covering physical healing and spiritual wholeness; the same formula appears at 7:50 (the sinful woman), 17:19 (the Samaritan leper), and 18:42 (blind Bartimaeus). <em>Poreuou eis eirēnēn</em> (go into peace) is the Hebrew <em>shalom</em> dismissal, the state of complete wellbeing.</p>',
    "49": '<p><strong>eti autou lalountos erchetai tis para tou archisyagōgou legōn hoti Tethnēken hē thygatēr sou</strong> — while he was still speaking, someone came from the house of the synagogue ruler saying: your daughter has died — <em>eti autou lalountos</em> (while he was still speaking) — the interruption arrives at the worst moment; the delay caused by the woman\'s healing has apparently cost the girl\'s life. <em>Tethnēken</em> (perfect: has died and is dead) is the final verdict. <strong>mēketi skyllve ton Didaskalon</strong> — do not trouble the Teacher any further — <em>skyllō</em> (to trouble, annoy, harass — originally to flay, then to pester) implies that the messenger considers the situation hopeless; there is no point in continuing to impose on Jesus.</p>',
    "50": '<p><strong>ho de Iēsous akousas apekrithē autō, Mē phobou, monon pisteue kai sōthēsetai</strong> — Jesus hearing answered him: do not fear, only believe and she will be saved/healed — <em>Mē phobou</em> (do not fear) is the divine comfort formula (cf. 1:13,30; 2:10; 5:10); it counters the messenger\'s despair with the perspective of divine possibility. <em>Monon pisteue</em> (only believe) — the single requirement is trust. <em>Sōthēsetai</em> (future: she will be saved/healed) — Jesus promises salvation before the miracle; the parent is to trust the promise before seeing the evidence. The pattern mirrors Abraham\'s faith (Gen 15:6).</p>',
    "51": '<p><strong>elthōn de eis tēn oikian ouk aphēken eiselthein tina syn autō ei mē Petron kai Iōannēn kai Iakōbon</strong> — arriving at the house he did not allow anyone to enter with him except Peter and John and James — the inner three disciples (the Petrine nucleus) are privileged witnesses; the same three will witness the Transfiguration (9:28) and, in Mark/Matthew, Gethsemane. <strong>kai ton patera tēs paidos kai tēn mētera</strong> — and the child\'s father and mother — the parents are necessary: they are the primary witnesses of their daughter\'s death and restoration. The crowd of mourners is excluded; the witnesses are carefully selected.</p>',
    "52": '<p><strong>eklaion de pantes kai ekoptonto autēn</strong> — all were weeping and mourning her — <em>koptō</em> (to beat, strike — reflexively to beat one\'s chest in mourning) is the formal mourning gesture (cf. 23:27,48; Rev 1:7). <strong>ho de eipen, Mē klaete, ou gar apethanen alla katheudei</strong> — he said: do not weep, for she has not died but is sleeping — <em>katheudō</em> (to sleep) is the euphemism for death in Jewish usage (cf. 1 Thess 4:13-14; 1 Cor 15:6,18,20,51); Jesus uses the metaphor prospectively — she will wake — but the mourners interpret it as denial of the obvious fact. The statement is simultaneously a medical judgment (she is in a death-like state) and a theological declaration (death in the presence of the Life-giver is sleep).</p>',
    "53": '<p><strong>kai kategelōn autou eidotes hoti apethanen</strong> — they were laughing at him, knowing that she had died — <em>katagelō</em> (to laugh at, mock, deride) is the mourners\' reaction to what they take as Jesus\'s absurd denial. <em>Eidotes hoti apethanen</em> (knowing that she had died — perfect: she has died and remains dead) — the mourners\' certainty becomes the foil against which the resurrection is measured. Their professional knowledge of death is about to be overturned. The laughter is not condemned by Luke; it is the inevitable response of those who measure reality by natural categories.</p>',
    "54": '<p><strong>autos de kratēsas tēs cheiros autēs ephōnēsen legōn, Hē pais, egeire</strong> — he took her hand and called out saying: Child, get up! — <em>kratēsas tēs cheiros</em> (taking hold of the hand) is direct physical contact with a corpse — ritually defiling (Num 19:11-16); Jesus touches what is impure and instead of being contaminated, imparts life. <em>Ephōnēsen</em> (called out, cried out — aorist of summoning) — not a whisper but a public summons, as Elijah and Elisha prayed over dead children (1 Kgs 17:21; 2 Kgs 4:34). <em>Hē pais, egeire</em> (Child, rise up!) — the diminutive address and the simple command capture both tenderness and authority.</p>',
    "55": '<p><strong>kai epestrepsen to pneuma autēs kai anestē parachrēma</strong> — her spirit returned and she stood up immediately — <em>Epestrepsen to pneuma autēs</em> (her spirit returned) — Luke\'s account of the mechanism: the <em>pneuma</em> (spirit, breath of life) is what God breathed into Adam (Gen 2:7) and what departs at death (Eccles 12:7; Ps 104:29-30); its return is the reversal of death. <em>Parachrēma</em> (immediately) is Luke\'s signature word for instantaneous divine action. <strong>kai diataxen autē dothēnai phagein</strong> — he commanded that something be given her to eat — the practical instruction verifies the reality of the restoration: a ghost does not eat; a truly revived child needs nourishment.</p>',
    "56": '<p><strong>kai existēsan hoi goneis autēs</strong> — her parents were astonished — <em>existēmi</em> (to be beside oneself with astonishment, to lose one\'s composure) is the strongest Greek amazement word. <strong>ho de parēngeilen autois mēdeni eipein to gegenōmenon</strong> — he commanded them to tell no one what had happened — the silence command applied to a resurrection: the contrast with the Gerasene demoniac (sent home to proclaim) is deliberate. In Jewish territory Jesus constrains proclamation (4:41; 5:14; 8:56); in Gentile territory he commissions it (8:39). The parents\' astonishment, the restoration of a twelve-year-old girl, and the command of silence close the double-miracle intercalation that began with another twelve-year duration.</p>',
  }
}

